import json
from base64 import urlsafe_b64decode, urlsafe_b64encode


def decode_and_verify(token):
    try:
        b = bytes(json.loads(urlsafe_b64decode(token).decode()))
        j = json.loads(str(b))
        return j['sub'], j["iss"], True

    except Exception as e:

        return "ERROR", None, False